from contextlib import contextmanager

config = {"model": "gpt-4o"}

@contextmanager
def using_model(name):
    previous = config["model"]
    config["model"] = name
    try:
        yield
    finally:
        config["model"] = previous   # always restored

with using_model("gpt-4o-mini"):
    print(config["model"])   # gpt-4o-mini
print(config["model"])       # gpt-4o (restored)
